from flask import Flask, request
from prometheus_client import Counter, Gauge, Histogram, generate_latest, CollectorRegistry
from prometheus_client import make_wsgi_app
from werkzeug.middleware.dispatcher import DispatcherMiddleware

app = Flask(__name__)

# Prometheus metrics
registry = CollectorRegistry()
request_counter = Counter('http_requests_total', 'Total HTTP Requests', ['method', 'endpoint'], registry=registry)
request_latency = Histogram('http_request_latency_seconds', 'HTTP Request Latency', ['endpoint'], registry=registry)
active_requests = Gauge('http_active_requests', 'Number of Active Requests', registry=registry)

@app.before_request
def before_request():
    active_requests.inc()

@app.after_request
def after_request(response):
    request_counter.labels(method=request.method, endpoint=request.path).inc()
    request_latency.labels(endpoint=request.path).observe(request.elapsed.total_seconds())
    active_requests.dec()
    return response

@app.route('/')
def index():
    return "Hello, World!"

@app.route('/metrics')
def metrics():
    return generate_latest(registry)

# WSGI app for Prometheus
app.wsgi_app = DispatcherMiddleware(app.wsgi_app, {
    '/metrics': make_wsgi_app(registry)
})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)